effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {

    vec2 st = acScreenNorm;
    vec2 fragSize = vec2(1.)/getTexSize(inputImg.size) * smoothing;
    float w  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x - fragSize.x, acScreenNorm.y) ).rgb*luminanceWeighting);
    float e  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x + fragSize.x, acScreenNorm.y) ).rgb*luminanceWeighting);
    float n  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x, acScreenNorm.y + fragSize.y) ).rgb*luminanceWeighting);
    float s  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x, acScreenNorm.y - fragSize.y) ).rgb*luminanceWeighting);
    float nw  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x - fragSize.x, acScreenNorm.y + fragSize.y) ).rgb*luminanceWeighting);
    float ne  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x + fragSize.x, acScreenNorm.y + fragSize.y) ).rgb*luminanceWeighting);
    float sw  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x - fragSize.x, acScreenNorm.y - fragSize.y) ).rgb*luminanceWeighting);
    float se  = dot(vec3(1.),texture2DCv(inputImg.texture, vec2(acScreenNorm.x + fragSize.x, acScreenNorm.y - fragSize.y) ).rgb*luminanceWeighting);

    float v = nw * 3. + n * 10. + ne * 3. + sw * -3. + s * -10. + se * -3.;
    float h = nw * -3. + w * -10. + sw * -3. + ne * 3. + e * 10. + se * 3.;
    float g = clamp(sqrt(h*h + v*v)-threshold, 0., 1.);

    vec4 texColor = texture2DCv(inputImg.texture, acScreenNorm);

    if( invert ) {
        gl_FragColor = vec4(1.-g,1.-g,1.-g,1.) * texColor.a;
    } else {
        gl_FragColor = vec4(g,g,g,1.) * texColor;
    }

}
